     1→import { _defaults } from './defaults.ts';
     2→import {
     3→  rtrim,
     4→  splitCells,
     5→  findClosingBracket,
     6→} from './helpers.ts';
     7→import type { Rules } from './rules.ts';
     8→import type { _Lexer } from './Lexer.ts';
     9→import type { Links, Tokens, Token } from './Tokens.ts';
    10→import type { MarkedOptions } from './MarkedOptions.ts';
    11→
    12→function outputLink(cap: string[], link: Pick<Tokens.Link, 'href' | 'title'>, raw: string, lexer: _Lexer, rules: Rules): Tokens.Link | Tokens.Image {
    13→  const href = link.href;
    14→  const title = link.title || null;
    15→  const text = cap[1].replace(rules.other.outputLinkReplace, '$1');
    16→
    17→  lexer.state.inLink = true;
    18→  const token: Tokens.Link | Tokens.Image = {
    19→    type: cap[0].charAt(0) === '!' ? 'image' : 'link',
    20→    raw,
    21→    href,
    22→    title,
    23→    text,
    24→    tokens: lexer.inlineTokens(text),
    25→  };
    26→  lexer.state.inLink = false;
    27→  return token;
    28→}
    29→
    30→function indentCodeCompensation(raw: string, text: string, rules: Rules) {
    31→  const matchIndentToCode = raw.match(rules.other.indentCodeCompensation);
    32→
    33→  if (matchIndentToCode === null) {
    34→    return text;
    35→  }
    36→
    37→  const indentToCode = matchIndentToCode[1];
    38→
    39→  return text
    40→    .split('\n')
    41→    .map(node => {
    42→      const matchIndentInNode = node.match(rules.other.beginningSpace);
    43→      if (matchIndentInNode === null) {
    44→        return node;
    45→      }
    46→
    47→      const [indentInNode] = matchIndentInNode;
    48→
    49→      if (indentInNode.length >= indentToCode.length) {
    50→        return node.slice(indentToCode.length);
    51→      }
    52→
    53→      return node;
    54→    })
    55→    .join('\n');
    56→}
    57→
    58→/**
    59→ * Tokenizer
    60→ */
    61→export class _Tokenizer<ParserOutput = string, RendererOutput = string> {
    62→  options: MarkedOptions<ParserOutput, RendererOutput>;
    63→  rules!: Rules; // set by the lexer
    64→  lexer!: _Lexer<ParserOutput, RendererOutput>; // set by the lexer
    65→
    66→  constructor(options?: MarkedOptions<ParserOutput, RendererOutput>) {
    67→    this.options = options || _defaults;
    68→  }
    69→
    70→  space(src: string): Tokens.Space | undefined {
    71→    const cap = this.rules.block.newline.exec(src);
    72→    if (cap && cap[0].length > 0) {
    73→      return {
    74→        type: 'space',
    75→        raw: cap[0],
    76→      };
    77→    }
    78→  }
    79→
    80→  code(src: string): Tokens.Code | undefined {
    81→    const cap = this.rules.block.code.exec(src);
    82→    if (cap) {
    83→      const text = cap[0].replace(this.rules.other.codeRemoveIndent, '');
    84→      return {
    85→        type: 'code',
    86→        raw: cap[0],
    87→        codeBlockStyle: 'indented',
    88→        text: !this.options.pedantic
    89→          ? rtrim(text, '\n')
    90→          : text,
    91→      };
    92→    }
    93→  }
    94→
    95→  fences(src: string): Tokens.Code | undefined {
    96→    const cap = this.rules.block.fences.exec(src);
    97→    if (cap) {
    98→      const raw = cap[0];
    99→      const text = indentCodeCompensation(raw, cap[3] || '', this.rules);
   100→
   101→      return {
   102→        type: 'code',
   103→        raw,
   104→        lang: cap[2] ? cap[2].trim().replace(this.rules.inline.anyPunctuation, '$1') : cap[2],
   105→        text,
   106→      };
   107→    }
   108→  }
   109→
   110→  heading(src: string): Tokens.Heading | undefined {
   111→    const cap = this.rules.block.heading.exec(src);
   112→    if (cap) {
   113→      let text = cap[2].trim();
   114→
   115→      // remove trailing #s
   116→      if (this.rules.other.endingHash.test(text)) {
   117→        const trimmed = rtrim(text, '#');
   118→        if (this.options.pedantic) {
   119→          text = trimmed.trim();
   120→        } else if (!trimmed || this.rules.other.endingSpaceChar.test(trimmed)) {
   121→          // CommonMark requires space before trailing #s
   122→          text = trimmed.trim();
   123→        }
   124→      }
   125→
   126→      return {
   127→        type: 'heading',
   128→        raw: cap[0],
   129→        depth: cap[1].length,
   130→        text,
   131→        tokens: this.lexer.inline(text),
   132→      };
   133→    }
   134→  }
   135→
   136→  hr(src: string): Tokens.Hr | undefined {
   137→    const cap = this.rules.block.hr.exec(src);
   138→    if (cap) {
   139→      return {
   140→        type: 'hr',
   141→        raw: rtrim(cap[0], '\n'),
   142→      };
   143→    }
   144→  }
   145→
   146→  blockquote(src: string): Tokens.Blockquote | undefined {
   147→    const cap = this.rules.block.blockquote.exec(src);
   148→    if (cap) {
   149→      let lines = rtrim(cap[0], '\n').split('\n');
   150→      let raw = '';
   151→      let text = '';
   152→      const tokens: Token[] = [];
   153→
   154→      while (lines.length > 0) {
   155→        let inBlockquote = false;
   156→        const currentLines = [];
   157→
   158→        let i;
   159→        for (i = 0; i < lines.length; i++) {
   160→          // get lines up to a continuation
   161→          if (this.rules.other.blockquoteStart.test(lines[i])) {
   162→            currentLines.push(lines[i]);
   163→            inBlockquote = true;
   164→          } else if (!inBlockquote) {
   165→            currentLines.push(lines[i]);
   166→          } else {
   167→            break;
   168→          }
   169→        }
   170→        lines = lines.slice(i);
   171→
   172→        const currentRaw = currentLines.join('\n');
   173→        const currentText = currentRaw
   174→          // precede setext continuation with 4 spaces so it isn't a setext
   175→          .replace(this.rules.other.blockquoteSetextReplace, '\n    $1')
   176→          .replace(this.rules.other.blockquoteSetextReplace2, '');
   177→        raw = raw ? `${raw}\n${currentRaw}` : currentRaw;
   178→        text = text ? `${text}\n${currentText}` : currentText;
   179→
   180→        // parse blockquote lines as top level tokens
   181→        // merge paragraphs if this is a continuation
   182→        const top = this.lexer.state.top;
   183→        this.lexer.state.top = true;
   184→        this.lexer.blockTokens(currentText, tokens, true);
   185→        this.lexer.state.top = top;
   186→
   187→        // if there is no continuation then we are done
   188→        if (lines.length === 0) {
   189→          break;
   190→        }
   191→
   192→        const lastToken = tokens.at(-1);
   193→
   194→        if (lastToken?.type === 'code') {
   195→          // blockquote continuation cannot be preceded by a code block
   196→          break;
   197→        } else if (lastToken?.type === 'blockquote') {
   198→          // include continuation in nested blockquote
   199→          const oldToken = lastToken as Tokens.Blockquote;
   200→          const newText = oldToken.raw + '\n' + lines.join('\n');
   201→          const newToken = this.blockquote(newText)!;
   202→          tokens[tokens.length - 1] = newToken;
   203→
   204→          raw = raw.substring(0, raw.length - oldToken.raw.length) + newToken.raw;
   205→          text = text.substring(0, text.length - oldToken.text.length) + newToken.text;
   206→          break;
   207→        } else if (lastToken?.type === 'list') {
   208→          // include continuation in nested list
   209→          const oldToken = lastToken as Tokens.List;
   210→          const newText = oldToken.raw + '\n' + lines.join('\n');
   211→          const newToken = this.list(newText)!;
   212→          tokens[tokens.length - 1] = newToken;
   213→
   214→          raw = raw.substring(0, raw.length - lastToken.raw.length) + newToken.raw;
   215→          text = text.substring(0, text.length - oldToken.raw.length) + newToken.raw;
   216→          lines = newText.substring(tokens.at(-1)!.raw.length).split('\n');
   217→          continue;
   218→        }
   219→      }
   220→
   221→      return {
   222→        type: 'blockquote',
   223→        raw,
   224→        tokens,
   225→        text,
   226→      };
   227→    }
   228→  }
   229→
   230→  list(src: string): Tokens.List | undefined {
   231→    let cap = this.rules.block.list.exec(src);
   232→    if (cap) {
   233→      let bull = cap[1].trim();
   234→      const isordered = bull.length > 1;
   235→
   236→      const list: Tokens.List = {
   237→        type: 'list',
   238→        raw: '',
   239→        ordered: isordered,
   240→        start: isordered ? +bull.slice(0, -1) : '',
   241→        loose: false,
   242→        items: [],
   243→      };
   244→
   245→      bull = isordered ? `\\d{1,9}\\${bull.slice(-1)}` : `\\${bull}`;
   246→
   247→      if (this.options.pedantic) {
   248→        bull = isordered ? bull : '[*+-]';
   249→      }
   250→
   251→      // Get next list item
   252→      const itemRegex = this.rules.other.listItemRegex(bull);
   253→      let endsWithBlankLine = false;
   254→      // Check if current bullet point can start a new List Item
   255→      while (src) {
   256→        let endEarly = false;
   257→        let raw = '';
   258→        let itemContents = '';
   259→        if (!(cap = itemRegex.exec(src))) {
   260→          break;
   261→        }
   262→
   263→        if (this.rules.block.hr.test(src)) { // End list if bullet was actually HR (possibly move into itemRegex?)
   264→          break;
   265→        }
   266→
   267→        raw = cap[0];
   268→        src = src.substring(raw.length);
   269→
   270→        let line = cap[2].split('\n', 1)[0].replace(this.rules.other.listReplaceTabs, (t: string) => ' '.repeat(3 * t.length));
   271→        let nextLine = src.split('\n', 1)[0];
   272→        let blankLine = !line.trim();
   273→
   274→        let indent = 0;
   275→        if (this.options.pedantic) {
   276→          indent = 2;
   277→          itemContents = line.trimStart();
   278→        } else if (blankLine) {
   279→          indent = cap[1].length + 1;
   280→        } else {
   281→          indent = cap[2].search(this.rules.other.nonSpaceChar); // Find first non-space char
   282→          indent = indent > 4 ? 1 : indent; // Treat indented code blocks (> 4 spaces) as having only 1 indent
   283→          itemContents = line.slice(indent);
   284→          indent += cap[1].length;
   285→        }
   286→
   287→        if (blankLine && this.rules.other.blankLine.test(nextLine)) { // Items begin with at most one blank line
   288→          raw += nextLine + '\n';
   289→          src = src.substring(nextLine.length + 1);
   290→          endEarly = true;
   291→        }
   292→
   293→        if (!endEarly) {
   294→          const nextBulletRegex = this.rules.other.nextBulletRegex(indent);
   295→          const hrRegex = this.rules.other.hrRegex(indent);
   296→          const fencesBeginRegex = this.rules.other.fencesBeginRegex(indent);
   297→          const headingBeginRegex = this.rules.other.headingBeginRegex(indent);
   298→          const htmlBeginRegex = this.rules.other.htmlBeginRegex(indent);
   299→
   300→          // Check if following lines should be included in List Item
   301→          while (src) {
   302→            const rawLine = src.split('\n', 1)[0];
   303→            let nextLineWithoutTabs;
   304→            nextLine = rawLine;
   305→
   306→            // Re-align to follow commonmark nesting rules
   307→            if (this.options.pedantic) {
   308→              nextLine = nextLine.replace(this.rules.other.listReplaceNesting, '  ');
   309→              nextLineWithoutTabs = nextLine;
   310→            } else {
   311→              nextLineWithoutTabs = nextLine.replace(this.rules.other.tabCharGlobal, '    ');
   312→            }
   313→
   314→            // End list item if found code fences
   315→            if (fencesBeginRegex.test(nextLine)) {
   316→              break;
   317→            }
   318→
   319→            // End list item if found start of new heading
   320→            if (headingBeginRegex.test(nextLine)) {
   321→              break;
   322→            }
   323→
   324→            // End list item if found start of html block
   325→            if (htmlBeginRegex.test(nextLine)) {
   326→              break;
   327→            }
   328→
   329→            // End list item if found start of new bullet
   330→            if (nextBulletRegex.test(nextLine)) {
   331→              break;
   332→            }
   333→
   334→            // Horizontal rule found
   335→            if (hrRegex.test(nextLine)) {
   336→              break;
   337→            }
   338→
   339→            if (nextLineWithoutTabs.search(this.rules.other.nonSpaceChar) >= indent || !nextLine.trim()) { // Dedent if possible
   340→              itemContents += '\n' + nextLineWithoutTabs.slice(indent);
   341→            } else {
   342→              // not enough indentation
   343→              if (blankLine) {
   344→                break;
   345→              }
   346→
   347→              // paragraph continuation unless last line was a different block level element
   348→              if (line.replace(this.rules.other.tabCharGlobal, '    ').search(this.rules.other.nonSpaceChar) >= 4) { // indented code block
   349→                break;
   350→              }
   351→              if (fencesBeginRegex.test(line)) {
   352→                break;
   353→              }
   354→              if (headingBeginRegex.test(line)) {
   355→                break;
   356→              }
   357→              if (hrRegex.test(line)) {
   358→                break;
   359→              }
   360→
   361→              itemContents += '\n' + nextLine;
   362→            }
   363→
   364→            if (!blankLine && !nextLine.trim()) { // Check if current line is blank
   365→              blankLine = true;
   366→            }
   367→
   368→            raw += rawLine + '\n';
   369→            src = src.substring(rawLine.length + 1);
   370→            line = nextLineWithoutTabs.slice(indent);
   371→          }
   372→        }
   373→
   374→        if (!list.loose) {
   375→          // If the previous item ended with a blank line, the list is loose
   376→          if (endsWithBlankLine) {
   377→            list.loose = true;
   378→          } else if (this.rules.other.doubleBlankLine.test(raw)) {
   379→            endsWithBlankLine = true;
   380→          }
   381→        }
   382→
   383→        list.items.push({
   384→          type: 'list_item',
   385→          raw,
   386→          task: !!this.options.gfm && this.rules.other.listIsTask.test(itemContents),
   387→          loose: false,
   388→          text: itemContents,
   389→          tokens: [],
   390→        });
   391→
   392→        list.raw += raw;
   393→      }
   394→
   395→      // Do not consume newlines at end of final item. Alternatively, make itemRegex *start* with any newlines to simplify/speed up endsWithBlankLine logic
   396→      const lastItem = list.items.at(-1);
   397→      if (lastItem) {
   398→        lastItem.raw = lastItem.raw.trimEnd();
   399→        lastItem.text = lastItem.text.trimEnd();
   400→      } else {
   401→        // not a list since there were no items
   402→        return;
   403→      }
   404→      list.raw = list.raw.trimEnd();
   405→
   406→      // Item child tokens handled here at end because we needed to have the final item to trim it first
   407→      for (const item of list.items) {
   408→        this.lexer.state.top = false;
   409→        item.tokens = this.lexer.blockTokens(item.text, []);
   410→        if (item.task) {
   411→          // Remove checkbox markdown from item tokens
   412→          item.text = item.text.replace(this.rules.other.listReplaceTask, '');
   413→          if (item.tokens[0]?.type === 'text' || item.tokens[0]?.type === 'paragraph') {
   414→            item.tokens[0].raw = item.tokens[0].raw.replace(this.rules.other.listReplaceTask, '');
   415→            item.tokens[0].text = item.tokens[0].text.replace(this.rules.other.listReplaceTask, '');
   416→            for (let i = this.lexer.inlineQueue.length - 1; i >= 0; i--) {
   417→              if (this.rules.other.listIsTask.test(this.lexer.inlineQueue[i].src)) {
   418→                this.lexer.inlineQueue[i].src = this.lexer.inlineQueue[i].src.replace(this.rules.other.listReplaceTask, '');
   419→                break;
   420→              }
   421→            }
   422→          }
   423→
   424→          const taskRaw = this.rules.other.listTaskCheckbox.exec(item.raw);
   425→          if (taskRaw) {
   426→            const checkboxToken: Tokens.Checkbox = {
   427→              type: 'checkbox',
   428→              raw: taskRaw[0] + ' ',
   429→              checked: taskRaw[0] !== '[ ]',
   430→            };
   431→            item.checked = checkboxToken.checked;
   432→            if (list.loose) {
   433→              if (item.tokens[0] && ['paragraph', 'text'].includes(item.tokens[0].type) && 'tokens' in item.tokens[0] && item.tokens[0].tokens) {
   434→                item.tokens[0].raw = checkboxToken.raw + item.tokens[0].raw;
   435→                item.tokens[0].text = checkboxToken.raw + item.tokens[0].text;
   436→                item.tokens[0].tokens.unshift(checkboxToken);
   437→              } else {
   438→                item.tokens.unshift({
   439→                  type: 'paragraph',
   440→                  raw: checkboxToken.raw,
   441→                  text: checkboxToken.raw,
   442→                  tokens: [checkboxToken],
   443→                });
   444→              }
   445→            } else {
   446→              item.tokens.unshift(checkboxToken);
   447→            }
   448→          }
   449→        }
   450→
   451→        if (!list.loose) {
   452→          // Check if list should be loose
   453→          const spacers = item.tokens.filter(t => t.type === 'space');
   454→          const hasMultipleLineBreaks = spacers.length > 0 && spacers.some(t => this.rules.other.anyLine.test(t.raw));
   455→
   456→          list.loose = hasMultipleLineBreaks;
   457→        }
   458→      }
   459→
   460→      // Set all items to loose if list is loose
   461→      if (list.loose) {
   462→        for (const item of list.items) {
   463→          item.loose = true;
   464→          for (const token of item.tokens) {
   465→            if (token.type === 'text') {
   466→              token.type = 'paragraph';
   467→            }
   468→          }
   469→        }
   470→      }
   471→
   472→      return list;
   473→    }
   474→  }
   475→
   476→  html(src: string): Tokens.HTML | undefined {
   477→    const cap = this.rules.block.html.exec(src);
   478→    if (cap) {
   479→      const token: Tokens.HTML = {
   480→        type: 'html',
   481→        block: true,
   482→        raw: cap[0],
   483→        pre: cap[1] === 'pre' || cap[1] === 'script' || cap[1] === 'style',
   484→        text: cap[0],
   485→      };
   486→      return token;
   487→    }
   488→  }
   489→
   490→  def(src: string): Tokens.Def | undefined {
   491→    const cap = this.rules.block.def.exec(src);
   492→    if (cap) {
   493→      const tag = cap[1].toLowerCase().replace(this.rules.other.multipleSpaceGlobal, ' ');
   494→      const href = cap[2] ? cap[2].replace(this.rules.other.hrefBrackets, '$1').replace(this.rules.inline.anyPunctuation, '$1') : '';
   495→      const title = cap[3] ? cap[3].substring(1, cap[3].length - 1).replace(this.rules.inline.anyPunctuation, '$1') : cap[3];
   496→      return {
   497→        type: 'def',
   498→        tag,
   499→        raw: cap[0],
   500→        href,
   501→        title,
   502→      };
   503→    }
   504→  }
   505→
   506→  table(src: string): Tokens.Table | undefined {
   507→    const cap = this.rules.block.table.exec(src);
   508→    if (!cap) {
   509→      return;
   510→    }
   511→
   512→    if (!this.rules.other.tableDelimiter.test(cap[2])) {
   513→      // delimiter row must have a pipe (|) or colon (:) otherwise it is a setext heading
   514→      return;
   515→    }
   516→
   517→    const headers = splitCells(cap[1]);
   518→    const aligns = cap[2].replace(this.rules.other.tableAlignChars, '').split('|');
   519→    const rows = cap[3]?.trim() ? cap[3].replace(this.rules.other.tableRowBlankLine, '').split('\n') : [];
   520→
   521→    const item: Tokens.Table = {
   522→      type: 'table',
   523→      raw: cap[0],
   524→      header: [],
   525→      align: [],
   526→      rows: [],
   527→    };
   528→
   529→    if (headers.length !== aligns.length) {
   530→      // header and align columns must be equal, rows can be different.
   531→      return;
   532→    }
   533→
   534→    for (const align of aligns) {
   535→      if (this.rules.other.tableAlignRight.test(align)) {
   536→        item.align.push('right');
   537→      } else if (this.rules.other.tableAlignCenter.test(align)) {
   538→        item.align.push('center');
   539→      } else if (this.rules.other.tableAlignLeft.test(align)) {
   540→        item.align.push('left');
   541→      } else {
   542→        item.align.push(null);
   543→      }
   544→    }
   545→
   546→    for (let i = 0; i < headers.length; i++) {
   547→      item.header.push({
   548→        text: headers[i],
   549→        tokens: this.lexer.inline(headers[i]),
   550→        header: true,
   551→        align: item.align[i],
   552→      });
   553→    }
   554→
   555→    for (const row of rows) {
   556→      item.rows.push(splitCells(row, item.header.length).map((cell, i) => {
   557→        return {
   558→          text: cell,
   559→          tokens: this.lexer.inline(cell),
   560→          header: false,
   561→          align: item.align[i],
   562→        };
   563→      }));
   564→    }
   565→
   566→    return item;
   567→  }
   568→
   569→  lheading(src: string): Tokens.Heading | undefined {
   570→    const cap = this.rules.block.lheading.exec(src);
   571→    if (cap) {
   572→      return {
   573→        type: 'heading',
   574→        raw: cap[0],
   575→        depth: cap[2].charAt(0) === '=' ? 1 : 2,
   576→        text: cap[1],
   577→        tokens: this.lexer.inline(cap[1]),
   578→      };
   579→    }
   580→  }
   581→
   582→  paragraph(src: string): Tokens.Paragraph | undefined {
   583→    const cap = this.rules.block.paragraph.exec(src);
   584→    if (cap) {
   585→      const text = cap[1].charAt(cap[1].length - 1) === '\n'
   586→        ? cap[1].slice(0, -1)
   587→        : cap[1];
   588→      return {
   589→        type: 'paragraph',
   590→        raw: cap[0],
   591→        text,
   592→        tokens: this.lexer.inline(text),
   593→      };
   594→    }
   595→  }
   596→
   597→  text(src: string): Tokens.Text | undefined {
   598→    const cap = this.rules.block.text.exec(src);
   599→    if (cap) {
   600→      return {
   601→        type: 'text',
   602→        raw: cap[0],
   603→        text: cap[0],
   604→        tokens: this.lexer.inline(cap[0]),
   605→      };
   606→    }
   607→  }
   608→
   609→  escape(src: string): Tokens.Escape | undefined {
   610→    const cap = this.rules.inline.escape.exec(src);
   611→    if (cap) {
   612→      return {
   613→        type: 'escape',
   614→        raw: cap[0],
   615→        text: cap[1],
   616→      };
   617→    }
   618→  }
   619→
   620→  tag(src: string): Tokens.Tag | undefined {
   621→    const cap = this.rules.inline.tag.exec(src);
   622→    if (cap) {
