   634→      return {
   635→        type: 'html',
   636→        raw: cap[0],
   637→        inLink: this.lexer.state.inLink,
   638→        inRawBlock: this.lexer.state.inRawBlock,
   639→        block: false,
   640→        text: cap[0],
   641→      };
   642→    }
   643→  }
   644→
   645→  link(src: string): Tokens.Link | Tokens.Image | undefined {
   646→    const cap = this.rules.inline.link.exec(src);
   647→    if (cap) {
   648→      const trimmedUrl = cap[2].trim();
