   650→        // commonmark requires matching angle brackets
   651→        if (!(this.rules.other.endAngleBracket.test(trimmedUrl))) {
   652→          return;
   653→        }
   654→
   655→        // ending angle bracket cannot be escaped
   656→        const rtrimSlash = rtrim(trimmedUrl.slice(0, -1), '\\');
   657→        if ((trimmedUrl.length - rtrimSlash.length) % 2 === 0) {
   658→          return;
   659→        }
   660→      } else {
   661→        // find closing parenthesis
   662→        const lastParenIndex = findClosingBracket(cap[2], '()');
   663→        if (lastParenIndex === -2) {
   664→          // more open parens than closed
   665→          return;
   666→        }
   667→
   668→        if (lastParenIndex > -1) {
   669→          const start = cap[0].indexOf('!') === 0 ? 5 : 4;
   670→          const linkLen = start + cap[1].length + lastParenIndex;
   671→          cap[2] = cap[2].substring(0, lastParenIndex);
   672→          cap[0] = cap[0].substring(0, linkLen).trim();
   673→          cap[3] = '';
   674→        }
   675→      }
   676→      let href = cap[2];
   677→      let title = '';
   678→      if (this.options.pedantic) {
   679→        // split pedantic href and title
   680→        const link = this.rules.other.pedanticHrefTitle.exec(href);
