   682→        if (link) {
   683→          href = link[1];
   684→          title = link[3];
   685→        }
   686→      } else {
   687→        title = cap[3] ? cap[3].slice(1, -1) : '';
   688→      }
   689→
   690→      href = href.trim();
   691→      if (this.rules.other.startAngleBracket.test(href)) {
   692→        if (this.options.pedantic && !(this.rules.other.endAngleBracket.test(trimmedUrl))) {
