   695→        } else {
   696→          href = href.slice(1, -1);
   697→        }
   698→      }
   699→      return outputLink(cap, {
   700→        href: href ? href.replace(this.rules.inline.anyPunctuation, '$1') : href,
   701→        title: title ? title.replace(this.rules.inline.anyPunctuation, '$1') : title,
   702→      }, cap[0], this.lexer, this.rules);
   703→    }
   704→  }
   705→
   706→  reflink(src: string, links: Links): Tokens.Link | Tokens.Image | Tokens.Text | undefined {
   707→    let cap;
   708→    if ((cap = this.rules.inline.reflink.exec(src))
   709→      || (cap = this.rules.inline.nolink.exec(src))) {
   710→      const linkString = (cap[2] || cap[1]).replace(this.rules.other.multipleSpaceGlobal, ' ');
   711→      const link = links[linkString.toLowerCase()];
   712→      if (!link) {
   713→        const text = cap[0].charAt(0);
   714→        return {
   715→          type: 'text',
   716→          raw: text,
   717→          text,
   718→        };
   719→      }
   720→      return outputLink(cap, link, cap[0], this.lexer, this.rules);
