   724→  emStrong(src: string, maskedSrc: string, prevChar = ''): Tokens.Em | Tokens.Strong | undefined {
   725→    let match = this.rules.inline.emStrongLDelim.exec(src);
   726→    if (!match) return;
   727→
   728→    // _ can't be between two alphanumerics. \p{L}\p{N} includes non-english alphabet/numbers as well
   729→    if (match[3] && prevChar.match(this.rules.other.unicodeAlphaNumeric)) return;
   730→
   731→    const nextChar = match[1] || match[2] || '';
   732→
   733→    if (!nextChar || !prevChar || this.rules.inline.punctuation.exec(prevChar)) {
   734→      // unicode Regex counts emoji as 1 char; spread into array for proper count (used multiple times below)
   735→      const lLength = [...match[0]].length - 1;
   736→      let rDelim, rLength, delimTotal = lLength, midDelimTotal = 0;
   737→
   738→      const endReg = match[0][0] === '*' ? this.rules.inline.emStrongRDelimAst : this.rules.inline.emStrongRDelimUnd;
   739→      endReg.lastIndex = 0;
   740→
   741→      // Clip maskedSrc to same section of string as src (move to lexer?)
   742→      maskedSrc = maskedSrc.slice(-1 * src.length + lLength);
   743→
   744→      while ((match = endReg.exec(maskedSrc)) != null) {
   745→        rDelim = match[1] || match[2] || match[3] || match[4] || match[5] || match[6];
   746→
   747→        if (!rDelim) continue; // skip single * in __abc*abc__
   748→
   749→        rLength = [...rDelim].length;
   750→
   751→        if (match[3] || match[4]) { // found another Left Delim
   752→          delimTotal += rLength;
   753→          continue;
   754→        } else if (match[5] || match[6]) { // either Left or Right Delim
   755→          if (lLength % 3 && !((lLength + rLength) % 3)) {
   756→            midDelimTotal += rLength;
   757→            continue; // CommonMark Emphasis Rules 9-10
   758→          }
   759→        }
   760→
   761→        delimTotal -= rLength;
   762→
   763→        if (delimTotal > 0) continue; // Haven't found enough closing delimiters
   764→
   765→        // Remove extra characters. *a*** -> *a*
   766→        rLength = Math.min(rLength, rLength + delimTotal + midDelimTotal);
   767→        // char length can be >1 for unicode characters;
   768→        const lastCharLength = [...match[0]][0].length;
   769→        const raw = src.slice(0, lLength + match.index + lastCharLength + rLength);
   770→
   771→        // Create `em` if smallest delimiter has odd char count. *a***
   772→        if (Math.min(lLength, rLength) % 2) {
   773→          const text = raw.slice(1, -1);
   774→          return {
   775→            type: 'em',
   776→            raw,
   777→            text,
   778→            tokens: this.lexer.inlineTokens(text),
   779→          };
   780→        }
   781→
   782→        // Create 'strong' if smallest delimiter has even char count. **a***
   783→        const text = raw.slice(2, -2);
   784→        return {
   785→          type: 'strong',
   786→          raw,
   787→          text,
   788→          tokens: this.lexer.inlineTokens(text),
   789→        };
   790→      }
   791→    }
   792→  }
   793→
   794→  codespan(src: string): Tokens.Codespan | undefined {
   795→    const cap = this.rules.inline.code.exec(src);
   796→    if (cap) {
   797→      let text = cap[2].replace(this.rules.other.newLineCharGlobal, ' ');
   798→      const hasNonSpaceChars = this.rules.other.nonSpaceChar.test(text);
   799→      const hasSpaceCharsOnBothEnds = this.rules.other.startingSpaceChar.test(text) && this.rules.other.endingSpaceChar.test(text);
   800→      if (hasNonSpaceChars && hasSpaceCharsOnBothEnds) {
   801→        text = text.substring(1, text.length - 1);
   802→      }
   803→      return {
   804→        type: 'codespan',
   805→        raw: cap[0],
   806→        text,
   807→      };
   808→    }
   809→  }
   810→
   811→  br(src: string): Tokens.Br | undefined {
   812→    const cap = this.rules.inline.br.exec(src);
   813→    if (cap) {
   814→      return {
   815→        type: 'br',
   816→        raw: cap[0],
   817→      };
   818→    }
   819→  }
