   821→  del(src: string, maskedSrc: string, prevChar = ''): Tokens.Del | undefined {
   822→    let match = this.rules.inline.delLDelim.exec(src);
   823→    if (!match) return;
   824→
   825→    const nextChar = match[1] || '';
   826→
   827→    if (!nextChar || !prevChar || this.rules.inline.punctuation.exec(prevChar)) {
   828→      // unicode Regex counts emoji as 1 char; spread into array for proper count
