   837→
   838→      while ((match = endReg.exec(maskedSrc)) != null) {
   839→        rDelim = match[1] || match[2] || match[3] || match[4] || match[5] || match[6];
   840→
   841→        if (!rDelim) continue;
   842→
   843→        rLength = [...rDelim].length;
   844→
   845→        if (rLength !== lLength) continue;
   846→
   847→        if (match[3] || match[4]) { // found another Left Delim
   848→          delimTotal += rLength;
   849→          continue;
   850→        }
   851→
   852→        delimTotal -= rLength;
   853→
   854→        if (delimTotal > 0) continue; // Haven't found enough closing delimiters
   855→
   856→        // Remove extra characters
   857→        rLength = Math.min(rLength, rLength + delimTotal);
   858→        // char length can be >1 for unicode characters
   859→        const lastCharLength = [...match[0]][0].length;
   860→        const raw = src.slice(0, lLength + match.index + lastCharLength + rLength);
   861→
   862→        // Create del token - only single ~ or double ~~ supported
   863→        const text = raw.slice(lLength, -lLength);
   864→        return {
   865→          type: 'del',
   866→          raw,
   867→          text,
   868→          tokens: this.lexer.inlineTokens(text),
   869→        };
   870→      }
   871→    }
   872→  }
   873→
   874→  autolink(src: string): Tokens.Link | undefined {
   875→    const cap = this.rules.inline.autolink.exec(src);
   876→    if (cap) {
   877→      let text, href;
   878→      if (cap[2] === '@') {
   879→        text = cap[1];
   880→        href = 'mailto:' + text;
   881→      } else {
   882→        text = cap[1];
   883→        href = text;
   884→      }
   885→
   886→      return {
   887→        type: 'link',
   888→        raw: cap[0],
   889→        text,
   890→        href,
   891→        tokens: [
   892→          {
   893→            type: 'text',
   894→            raw: text,
   895→            text,
   896→          },
   897→        ],
   898→      };
   899→    }
   900→  }
   901→
   902→  url(src: string): Tokens.Link | undefined {
   903→    let cap;
