   905→      let text, href;
   906→      if (cap[2] === '@') {
   907→        text = cap[0];
   908→        href = 'mailto:' + text;
   909→      } else {
   910→        // do extended autolink path validation
   911→        let prevCapZero;
   912→        do {
   913→          prevCapZero = cap[0];
   914→          cap[0] = this.rules.inline._backpedal.exec(cap[0])?.[0] ?? '';
   915→        } while (prevCapZero !== cap[0]);
   916→        text = cap[0];
   917→        if (cap[1] === 'www.') {
   918→          href = 'http://' + cap[0];
   919→        } else {
   920→          href = cap[0];
   921→        }
   922→      }
   923→      return {
   924→        type: 'link',
   925→        raw: cap[0],
   926→        text,
   927→        href,
   928→        tokens: [
   929→          {
   930→            type: 'text',
   931→            raw: text,
   932→            text,
   933→          },
   934→        ],
   935→      };
   936→    }
   937→  }
   938→
   939→  inlineText(src: string): Tokens.Text | undefined {
   940→    const cap = this.rules.inline.text.exec(src);
   941→    if (cap) {
   942→      const escaped = this.lexer.state.inRawBlock;
   943→      return {
   944→        type: 'text',
   945→        raw: cap[0],
   946→        text: cap[0],
   947→        escaped,
   948→      };
   949→    }
   950→  }
   951→}
